import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { writable } from 'svelte/store';
import { hints } from './hints';
import { createGame, createSudoku } from '../../../domain/index';

/**
 * 创建一个 9x9 的空数独盘面。
 * @returns {number[][]} 全部填 0 的二维数组。
 */
function createEmptyGrid() {
    return Array.from({ length: 9 }, () => Array(9).fill(0));
}

/**
 * 当前游戏领域对象。
 * 这里由 adapter 持有，UI 不直接访问它。
 * @type {import('../../../domain/Game').Game}
 */
let game = createGame({ sudoku: createSudoku(createEmptyGrid()) });

/**
 * 初始题面状态，用于 UI 展示。
 * @type {import('svelte/store').Writable<number[][]>}
 */
const gridState = writable(createEmptyGrid());

/**
 * 用户当前填写的盘面状态。
 * @type {import('svelte/store').Writable<number[][]>}
 */
const userGridState = writable(createEmptyGrid());

/**
 * 当前不合法单元格坐标集合。
 * 坐标格式为 "x,y"。
 * @type {import('svelte/store').Writable<string[]>}
 */
const invalidCellsState = writable([]);

/**
 * 将领域对象中的最新快照同步到 Svelte store。
 * 这是 adapter 的核心同步入口。
 */
function syncFromGame() {
    const view = game.getViewState();
    gridState.set(view.puzzleGrid);
    userGridState.set(view.userGrid);
    invalidCellsState.set(view.invalidCells);
}

syncFromGame();

/**
 * 创建面向 UI 的 grid store adapter。
 * 它既提供可订阅状态，也提供游戏命令方法。
 * @returns {{
 *   subscribe: import('svelte/store').Readable<number[][]>['subscribe'],
 *   generate: (difficulty: string) => void,
 *   decodeSencode: (sencode: string) => void,
 *   get: (gridStore: number[][], x: number, y: number) => number,
 *   getSencode: (gridStore?: number[][]) => string,
 *   undo: () => void,
 *   redo: () => void,
 *   canUndo: () => boolean,
 *   canRedo: () => boolean
 * }}
 */
function createGrid() {
    return {
        subscribe: gridState.subscribe,

        /**
         * 根据难度生成新题目。
         * @param {string} difficulty 题目难度。
         */
        generate(difficulty) {
            const puzzleArray = generateSudoku(difficulty);
            game = createGame({ sudoku: createSudoku(puzzleArray) });
            syncFromGame();
        },

        /**
         * 从 sencode 字符串加载题目。
         * @param {string} sencode 编码后的题面字符串。
         */
        decodeSencode(sencode) {
            const puzzleArray = decodeSencode(sencode);
            game = createGame({ sudoku: createSudoku(puzzleArray) });
            syncFromGame();
        },

        /**
         * 读取指定坐标上的值。
         * @param {number[][]} gridStore 当前盘面数组。
         * @param {number} x 列索引。
         * @param {number} y 行索引。
         * @returns {number} 该位置的数字。
         */
        get(gridStore, x, y) {
            return gridStore[y][x];
        },

        /**
         * 将盘面编码为 sencode 字符串。
         * @param {number[][]} gridStore 需要编码的盘面。
         * @returns {string} 编码后的字符串。
         */
        getSencode(gridStore) {
            if (gridStore) return encodeSudoku(gridStore);
            return encodeSudoku(game.sudoku.getGrid());
        },

        /**
         * 撤销一步操作。
         */
        undo() {
            game.undo();
            syncFromGame();
        },

        /**
         * 重做一步操作。
         */
        redo() {
            game.redo();
            syncFromGame();
        },

        /**
         * 当前是否可以撤销。
         * @returns {boolean} 是否存在可撤销历史。
         */
        canUndo() {
            return game.canUndo();
        },

        /**
         * 当前是否可以重做。
         * @returns {boolean} 是否存在可重做历史。
         */
        canRedo() {
            return game.canRedo();
        },
    };
}

/**
 * 创建面向用户输入的 userGrid store adapter。
 * 主要负责把 UI 操作转发到领域对象。
 * @returns {{
 *   subscribe: import('svelte/store').Readable<number[][]>['subscribe'],
 *   set: (pos: {x: number, y: number}, value: number) => void,
 *   applyHint: (pos: {x: number, y: number}) => void
 * }}
 */
function createUserGrid() {
    return {
        subscribe: userGridState.subscribe,

        /**
         * 在指定位置填写数字。
         * @param {{x: number, y: number}} pos 光标位置。
         * @param {number} value 要填写的数字。
         */
        set(pos, value) {
            game.guess({ row: pos.y, col: pos.x, value });
            syncFromGame();
        },

        /**
         * 对指定位置应用提示。
         * @param {{x: number, y: number}} pos 光标位置。
         */
        applyHint(pos) {
            hints.useHint();
            const solvedGrid = solveSudoku(game.sudoku.getGrid());
            if (!solvedGrid) return;
            const value = solvedGrid[pos.y][pos.x];
            game.guess({ row: pos.y, col: pos.x, value });
            syncFromGame();
        },
    };
}

/**
 * 对外暴露的初始题面 store。
 */
export const grid = createGrid();

/**
 * 对外暴露的用户输入盘面 store。
 */
export const userGrid = createUserGrid();

/**
 * 对外暴露的不合法单元格 store。
 */
export const invalidCells = {
    subscribe: invalidCellsState.subscribe,
};